sql:
SELECT title, date_time
FROM spectrometry_data
ORDER BY date_time DESC;

SELECT MAX(date_time) AS latest_date_time
FROM spectrometry_data
WHERE material_type = 'reference material';

external_knowledge:
- Counts per second (CPS) is a measure of the rate at which particles or signals are detected by a spectrometer.; 
- Material type refers to the type of sample being analyzed, such as a reference material or a sample.; 
- The latest version of each data entry refers to the most recent version of the data, as indicated by the highest version number.; 
- The lab name and approver name are included to provide context and accountability for the data.

sql:
SELECT title
FROM spectrometry_data
ORDER BY title ASC;

SELECT data_id
FROM spectrometry_data
ORDER BY data_id;

SELECT material_type, AVG(temperature) AS average_temperature
FROM spectrometry_data
GROUP BY material_type;

SELECT data_id, AVG(ybO_total_cps) AS average_ybO_cps
FROM spectrometry_data
GROUP BY data_id;

SELECT data_id, title, date_time
FROM spectrometry_data
ORDER BY date_time DESC;
